async (params, browser) => {
  // Open Jira issue
  await browser.open(`${params.jira_url}/browse/${params.issue_key}`)

  // Let page load
  await browser.wait(2000)

  // Update issue via REST API
  const result = await browser.evaluate(`const baseUrl = params.jira_url.replace(/\/$/, ''); const fields = {}; const summary = params.summary; if (summary) fields.summary = summary; const desc = params.description; if (desc) fields.description = { type: 'doc', version: 1, content: [{ type: 'paragraph', content: [{ type: 'text', text: desc }] }] }; const priority = params.priority; if (priority) fields.priority = { name: priority }; if (Object.keys(fields).length === 0) return { success: false, message: 'No fields to update' }; const resp = await fetch(baseUrl + '/rest/api/3/issue/' + params.issue_key + '', { method: 'PUT', headers: { 'Content-Type': 'application/json' }, credentials: 'same-origin', body: JSON.stringify({ fields }) }); if (!resp.ok) { const err = await resp.text(); throw new Error('Update failed: ' + resp.status + ' ' + err); } return { success: true, key: '' + params.issue_key + '', updated_fields: Object.keys(fields) }`)

  return result
}
